"use client"

import { useContext } from "react"
import { ProfileContext } from "../../context/profile/ProfileContext"
import Spinner from "../layout/Spinner"

const LeetcodeStats = () => {
  const { leetcodeStats, loading } = useContext(ProfileContext)

  if (loading) {
    return <Spinner />
  }

  if (!leetcodeStats) {
    return (
      <div className="bg-white p-4 rounded-lg shadow-md">
        <h3 className="text-xl font-semibold mb-2">LeetCode Stats</h3>
        <p>Add your LeetCode profile to see stats here.</p>
      </div>
    )
  }

  // Calculate active days correctly from recent submissions
  const calculateActiveDays = () => {
    if (!leetcodeStats.recentSubmissions || leetcodeStats.recentSubmissions.length === 0) {
      return 0
    }

    // Extract unique dates from submissions
    const uniqueDates = new Set()
    leetcodeStats.recentSubmissions.forEach((submission) => {
      if (submission.timestamp) {
        const date = new Date(submission.timestamp * 1000).toDateString()
        uniqueDates.add(date)
      }
    })

    return uniqueDates.size
  }

  // Calculate streak from submissions
  const calculateStreak = () => {
    if (!leetcodeStats.recentSubmissions || leetcodeStats.recentSubmissions.length === 0) {
      return 0
    }

    // Group submissions by date
    const submissionsByDate = {}
    leetcodeStats.recentSubmissions.forEach((submission) => {
      if (submission.timestamp) {
        const date = new Date(submission.timestamp * 1000).toDateString()
        submissionsByDate[date] = true
      }
    })

    // Calculate current streak
    let streak = 0
    const today = new Date()

    for (let i = 0; i < 365; i++) {
      const checkDate = new Date(today)
      checkDate.setDate(today.getDate() - i)
      const dateString = checkDate.toDateString()

      if (submissionsByDate[dateString]) {
        streak++
      } else if (i > 0) {
        // Don't break on first day if no submission today
        break
      }
    }

    return streak
  }

  // Format timestamp
  const formatTimestamp = (timestamp) => {
    if (!timestamp) return "N/A"
    const date = new Date(timestamp * 1000)
    return date.toLocaleString()
  }

  // Safe formatting for percentages
  const formatPercentage = (value) => {
    if (value === null || value === undefined) return "N/A"
    return value.toFixed(1) + "%"
  }

  const activeDays = calculateActiveDays()
  const currentStreak = calculateStreak()

  return (
    <div className="bg-white p-4 rounded-lg shadow-md">
      <h3 className="text-xl font-semibold mb-4">LeetCode Stats</h3>

      <div className="grid grid-cols-2 gap-4 mb-4">
        <div className="bg-gray-100 p-3 rounded">
          <p className="text-sm text-gray-600">Total Solved</p>
          <p className="text-xl font-bold">{leetcodeStats.totalSolved || 0}</p>
        </div>
        <div className="bg-gray-100 p-3 rounded">
          <p className="text-sm text-gray-600">Ranking</p>
          <p className="text-xl font-bold">{leetcodeStats.ranking || "N/A"}</p>
        </div>
        <div className="bg-blue-50 p-3 rounded">
          <p className="text-sm text-gray-600">Active Days</p>
          <p className="text-xl font-bold text-blue-600">{activeDays}</p>
        </div>
        <div className="bg-green-50 p-3 rounded">
          <p className="text-sm text-gray-600">Current Streak</p>
          <p className="text-xl font-bold text-green-600">{currentStreak} days</p>
        </div>
      </div>

      <div className="mb-4">
        <h4 className="font-semibold mb-2">Problem Solving</h4>
        <div className="flex items-center mb-2">
          <div className="w-full bg-gray-200 rounded-full h-4">
            <div
              className="bg-green-500 h-4 rounded-full"
              style={{
                width: `${((leetcodeStats.easySolved || 0) / (leetcodeStats.totalSolved || 1)) * 100}%`,
              }}
            ></div>
          </div>
          <span className="ml-2 text-sm font-medium">Easy: {leetcodeStats.easySolved || 0}</span>
        </div>
        <div className="flex items-center mb-2">
          <div className="w-full bg-gray-200 rounded-full h-4">
            <div
              className="bg-yellow-500 h-4 rounded-full"
              style={{
                width: `${((leetcodeStats.mediumSolved || 0) / (leetcodeStats.totalSolved || 1)) * 100}%`,
              }}
            ></div>
          </div>
          <span className="ml-2 text-sm font-medium">Medium: {leetcodeStats.mediumSolved || 0}</span>
        </div>
        <div className="flex items-center">
          <div className="w-full bg-gray-200 rounded-full h-4">
            <div
              className="bg-red-500 h-4 rounded-full"
              style={{
                width: `${((leetcodeStats.hardSolved || 0) / (leetcodeStats.totalSolved || 1)) * 100}%`,
              }}
            ></div>
          </div>
          <span className="ml-2 text-sm font-medium">Hard: {leetcodeStats.hardSolved || 0}</span>
        </div>
      </div>

      {leetcodeStats.beatsPercentage && leetcodeStats.beatsPercentage.length > 0 && (
        <div className="mb-4">
          <h4 className="font-semibold mb-2">Beats Percentage</h4>
          <div className="grid grid-cols-3 gap-2">
            {leetcodeStats.beatsPercentage.map((item, index) => (
              <div key={index} className="bg-gray-100 p-2 rounded text-center">
                <p className="text-xs text-gray-600">{item.difficulty || "Unknown"}</p>
                <p className="text-lg font-bold">{formatPercentage(item.percentage)}</p>
              </div>
            ))}
          </div>
        </div>
      )}

      {leetcodeStats.topTags && leetcodeStats.topTags.length > 0 && (
        <div className="mb-4">
          <h4 className="font-semibold mb-2">Top Tags</h4>
          <div className="grid grid-cols-2 gap-2">
            {leetcodeStats.topTags.map((tag, index) => (
              <div key={index} className="bg-gray-100 p-2 rounded">
                <p className="text-sm font-medium">{tag.tagName || "Unknown"}</p>
                <p className="text-xs text-gray-600">Solved: {tag.problemsSolved || 0}</p>
              </div>
            ))}
          </div>
        </div>
      )}

      {leetcodeStats.recentSubmissions && leetcodeStats.recentSubmissions.length > 0 && (
        <div className="mt-4">
          <h4 className="font-semibold mb-2">Recent Submissions</h4>
          <div className="max-h-60 overflow-y-auto">
            <ul className="divide-y">
              {leetcodeStats.recentSubmissions.map((submission, index) => (
                <li key={index} className="py-2">
                  <a
                    href={submission.titleSlug ? `https://leetcode.com/problems/${submission.titleSlug}` : "#"}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="text-blue-600 hover:underline text-sm font-medium"
                  >
                    {submission.title || "Unknown Problem"}
                  </a>
                  <div className="flex justify-between text-xs mt-1">
                    <span
                      className={`${
                        submission.statusDisplay === "Accepted"
                          ? "text-green-600"
                          : submission.statusDisplay === "Wrong Answer"
                            ? "text-red-600"
                            : "text-yellow-600"
                      }`}
                    >
                      {submission.statusDisplay || "Unknown Status"}
                    </span>
                    <span className="text-gray-500">{formatTimestamp(submission.timestamp)}</span>
                  </div>
                  <span className="text-xs bg-gray-100 px-1 rounded">{submission.lang || "Unknown Language"}</span>
                </li>
              ))}
            </ul>
          </div>
        </div>
      )}

      {leetcodeStats.badges && leetcodeStats.badges.length > 0 && (
        <div className="mt-4">
          <h4 className="font-semibold mb-2">Badges</h4>
          <div className="flex flex-wrap gap-2">
            {leetcodeStats.badges.map((badge, index) => (
              <div key={index} className="bg-gray-100 p-2 rounded text-center">
                <p className="text-xs">{badge.displayName || "Unknown Badge"}</p>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  )
}

export default LeetcodeStats
